data: {"type":"response.output_item.done","item":{"type":"fabric_dataagent_preview_call_output","id":"fco_0b7e2a2566f80b470069a28a02e3688197bd95888a54d65674","agent_reference":{"type":"agent_reference","name":"MyAgent","version":"463"},"response_id":"resp_0b7e2a2566f80b470069a289e37b288197a4256f1837637fd7","call_id":"call_06aabdaa82a84b968892723ddaafe0c3","output":"{\"documents\":[{\"id\":\"61a49e9f-c747-4998-84b0-b6f877eb4b24\",\"content\":\"Here are some notable weather events in Texas:\\n\\n- **High Wind (Dec 30\\u201331, 2007):** Gusts up to 71 mph at McDonald Observatory, Davis Mountains.\\n- **Heavy Snow (Dec 27\\u201328, 2007):** Four inches near Perryton and Spearman, causing dangerous travel conditions.\\n- **Tornadoes (Dec 27, 2007):** Tornadoes observed near Slaton/Southland and north of Lubbock; no reported damage.\\n- **Winter Weather Accident (Dec 27, 2007):** Icy roads led to a fatal single-vehicle accident on US 287\\u2014one death, three injuries.\\n- **Major Winter Storm (Dec 22, 2007):** Whiteout conditions east of Amarillo caused multi-car pileups\\u2014two fatalities, 150\\u002B injuries, and over $1.6 million in damages.\\n\\nWould you like information for a different period or a specific weather event type?\\n\",\"filepath\":\"fabric://response\",\"title\":\"Fabric Response for: weather events in Texas\",\"url\":\"https://msit.fabric.microsoft.com/groups/409e30ce-b2ad-4c80-a54d-d645227322e4/aiskills/98042b9e-11cb-422d-bd97-5873411aa7c8/stage/published/threads/thread_MuEWccMsL1Y7Q2gTKDe0QxyT/runs/run_fabDf0PtnrxWKdrZSryVUPBQoOAl/question/msg_VI2wYFfc2jVt3A5Nwbp9NA4X/source/foundry\",\"metadata\":\"{\\u0022source\\u0022:\\u0022azure_fabric\\u0022,\\u0022query\\u0022:\\u0022weather events in Texas\\u0022,\\u0022data_agent_url\\u0022:\\u0022https://msit.fabric.microsoft.com/groups/409e30ce-b2ad-4c80-a54d-d645227322e4/aiskills/98042b9e-11cb-422d-bd97-5873411aa7c8/stage/published/threads/thread_MuEWccMsL1Y7Q2gTKDe0QxyT/runs/run_fabDf0PtnrxWKdrZSryVU